import Hero from"../components/hero.js";import ActivityCard from"../components/activityCard.js";import EngagementCard from"../components/engagementCard.js";import ProductGrid from"../components/productGrid.js";import ProductModal from"../components/productModal.js";import FilterBar from"../components/filterBar.js";import ContactForm from"../components/contactForm.js";import Footer from"../components/footer.js";import Partners from"../components/partners.js";import LoadingScreen from"../components/loadingScreen.js";import Animations from"./animations.js";import MobileMenu from"./mobileMenu.js";import Toast from"./toast.js";import Analytics from"./analytics.js";import SEO from"./seo.js";import DarkMode from"./darkMode.js";import UXRefinements from"./ux-refinements.js";window.Toast=Toast;window.Analytics=Analytics;const links=["css/hero.css","css/partenaires.css","css/productGrid.css","css/productModal.css","css/filterBar.css"];links.forEach(href=>{const link=document.createElement("link");link.rel="stylesheet";link.href=href;document.head.appendChild(link)});async function init(){LoadingScreen.render();try{const response=await fetch("config.json");if(!response.ok)throw new Error("Could not load config.json");const config=await response.json();MobileMenu.init();Toast.init();Analytics.init();SEO.init(config);DarkMode.init();UXRefinements.init();if(document.querySelector("#hero-slider-container")){Hero.render("#hero-slider-container",config.hero)}if(document.querySelector("#activities-container")){ActivityCard.render("#activities-container",config.activities)}if(document.querySelector("#engagement-cards-container")){const engagementData=[{title:"Expertise Durable",icon:"fas fa-award",description:"Madame Fofana Geneviève, Gérante, pilote KIRAM PHARMA depui 2018 avec une rigueur éthique et scientifique."},{title:"Proximité Stratégique",icon:"fas fa-map-marked-alt",description:"Basés à Abidjan (Cocody Angré Djibi), nous assurons une disponibilité totale pour nos partenaires et patients."},{title:"Vision Pharmaceutique",icon:"fas fa-lightbulb",description:"Représenter les meilleurs laboratoires internationaux pour offrir l'excellence pharmaceutique en Côte d'Ivoire."}];EngagementCard.render("#engagement-cards-container",engagementData)}const gridContainer=document.querySelector("#product-grid-container");if(gridContainer&&config.products){gridContainer.innerHTML=`\n            <div style="display: grid; grid-template-columns: repeat(auto-fill, minmax(300px, 1fr)); gap: 30px;">\n                ${Array(3).fill('<div class="skeleton" style="height: 400px; border-radius: 20px;"></div>').join("")}\n            </div>\n        `;setTimeout(()=>{ProductGrid.render("#product-grid-container",config.products);Animations.refresh();Animations.initMicroInteractions()},800)}if(document.querySelector("#product-modal-container")&&config.products){ProductModal.render("#product-modal-container",config.products)}if(document.querySelector("#filter-bar-container")&&config.products){FilterBar.render("#filter-bar-container",config.products)}const partnersContainer=document.querySelector("#partners-section-container");if(partnersContainer){try{const partnersRes=await fetch("sections/partenaires.html");if(partnersRes.ok){const partnersHtml=await partnersRes.text();partnersContainer.innerHTML=partnersHtml;if(config.partners){Partners.render("#partners-grid-container",config.partners)}}}catch(e){console.warn("Partners error:",e)}}if(document.querySelector("#contact-container")){ContactForm.render("#contact-container",config)}if(document.querySelector("#footer-container")){Footer.render("#footer-container",config)}Animations.initReveal();const ctaContainer=document.querySelector("#sticky-cta-container");if(ctaContainer){ctaContainer.innerHTML=`\n            <a href="#contact" class="sticky-cta">\n                <i class="fas fa-paper-plane"></i>\n                <span>Parler à un expert</span>\n            </a>\n        `;const ctaEl=ctaContainer.querySelector(".sticky-cta");ctaEl.addEventListener("click",()=>{Analytics.trackEvent("Contact","Click CTA Sticky");Toast.show("Redirection vers le formulaire...","info")})}setTimeout(()=>{LoadingScreen.hide()},500)}catch(error){console.error("KIRAM Init Error:",error);if(window.Toast)Toast.show("Erreur de chargement des données","error")}}document.addEventListener("DOMContentLoaded",init);